mapper.delete:
delete from

where 1=1

	and SHOPPINGCAR_ID = #{SHOPPINGCAR_ID}


	and USERNAME = #{USERNAME}

delete from

where 1=1
and GOODS_ATTRIBUTE_ID = #{GOODS_ATTRIBUTE_ID}
and USERNAME = #{USERNAME}

mapper.select:
select
from
where USERNAME = #{USERNAME} and GOODS_ATTRIBUTE_ID = #{GOODS_ATTRIBUTE_ID}

select SHOP_SHOPPINGCAR.GOODS_ID, SHOP_SHOPPINGCAR.GOODS_NAME, SHOP_SHOPPINGCAR.GOODS_ATTRIBUTE_ID, SHOP_SHOPPINGCAR.GOODS_ATTRIBUTE, SHOP_SHOPPINGCAR.GOODS_NUM, SHOP_SHOPPINGCAR.GOODS_PRICE, SHOP_SHOPPINGCAR.GOODS_NUM*SHOP_SHOPPINGCAR.GOODS_PRICE as GOODS_TOTAL, SHOP_SHOPPINGCAR.USERNAME, SHOP_SHOPPINGCAR.REALNAME, SHOP_SHOPPINGCAR.ADDTIME, SHOP_SHOPPINGCAR.SHOPPINGCAR_ID, substring_index(SHOP_GOODS.GOODS_PIC,',',1) as GOODS_PIC from SHOP_SHOPPINGCAR left join SHOP_GOODS on SHOP_SHOPPINGCAR.GOODS_ID = SHOP_GOODS.GOODS_ID where 1=1
and (
SHOP_SHOPPINGCAR.GOODS_NAME LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') )
and ADDTIME >= #{pd.lastStart}
and ADDTIME <= #{pd.lastEnd}
and USERNAME = #{pd.USERNAME}
and GOODS_ID = #{pd.GOODS_ID}
and GOODS_FORSALE = 1
and GOODS_ATTRIBUTE_ID = #{pd.GOODS_ATTRIBUTE_ID}
and (GOODS_DELFLAG is null or GOODS_DELFLAG != 1)
